Modified greedy insertion with cost-delta evaluation across all assign slots, preserving original assign ordering while trying both non-empty and empty assigns, with fallback creation of new assign if needed.}
func InsertShips(dispatch Dispatch, oris, dess []Station, total_ship int) Dispatch {
	orderCount := len(oris)
	for shipIdx := 0; shipIdx < orderCount; shipIdx++ {
		bestAssignIdx := -1
		bestDelta := 1e100
		origCosts := make([]float64, dispatch.AssignsLen)
		for i := 0; i < dispatch.AssignsLen; i++ {
			origCosts[i] = dispatch.Assigns[i].Cost
		}
		foundAny := false
		for tryIdx := 0; tryIdx < dispatch.AssignsLen+1; tryIdx++ {
			assignSlot := tryIdx
			if assignSlot >= dispatch.AssignsLen {
				continue
			}
			savedState := dispatch.Assigns[assignSlot]
			addOk := dispatch.Assigns[assignSlot].AddShip(total_ship+shipIdx, oris[shipIdx], dess[shipIdx])
			if addOk {
				dispatch.Assigns[assignSlot].GenRoute()
				newCost := dispatch.Assigns[assignSlot].Cost
				delta := newCost - origCosts[assignSlot]
				if newCost >= 0 && delta < bestDelta {
					bestDelta = delta
					bestAssignIdx = assignSlot
					foundAny = true
				}
				dispatch.Assigns[assignSlot] = savedState
				dispatch.Assigns[assignSlot].GenRoute()
			}
		}
		if !foundAny || bestAssignIdx == -1 {
			fallbackIdx := dispatch.AssignsLen
			if fallbackIdx < MAXASSIGNS {
				dispatch.Assigns[fallbackIdx].AddShip(total_ship+shipIdx, oris[shipIdx], dess[shipIdx])
				dispatch.Assigns[fallbackIdx].GenRoute()
				dispatch.AssignsLen++
			}
		} else {
			dispatch.Assigns[bestAssignIdx].AddShip(total_ship+shipIdx, oris[shipIdx], dess[shipIdx])
			dispatch.Assigns[bestAssignIdx].GenRoute()
		}
	}
	if dispatch.AssignsLen == 0 && orderCount > 0 {
		for shipIdx := 0; shipIdx < orderCount; shipIdx++ {
			slot := dispatch.AssignsLen
			if slot < MAXASSIGNS {
				dispatch.Assigns[slot].AddShip(total_ship+shipIdx, oris[shipIdx], dess[shipIdx])
				dispatch.Assigns[slot].GenRoute()
				dispatch.AssignsLen++
			}
		}
	}
	dispatch.RenewnTotalCost()
	return dispatch

